import React, { useState, useEffect } from 'react';
import { Link, useSearchParams } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useArticle } from '../context/ArticleContext';
import { API_BASE_URL } from '../config';

const Home = () => {
  const [articles, setArticles] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showRegisterModal, setShowRegisterModal] = useState(false);
  const { user } = useAuth();
  const { getArticleStats } = useArticle();
  const [searchParams] = useSearchParams();
  const searchTerm = searchParams.get('search');

  useEffect(() => {
    fetchArticles();
  }, [searchTerm]);

  const fetchArticles = async () => {
    try {
      const url = searchTerm 
        ? `${API_BASE_URL}/articles?search=${searchTerm}`
        : `${API_BASE_URL}/articles`;
      const res = await fetch(url);
      const data = await res.json();

      if (!user) {
        setArticles(data.slice(0, 3));
      } else {
        setArticles(data);
      }
      setLoading(false);
    } catch (error) {
      console.error('Failed to fetch articles:', error);
      setLoading(false);
    }
  };

  const handleLoadMore = () => {
    if (!user) {
      setShowRegisterModal(true);
    }
  };

  if (loading) return <div style={styles.loading}>ÕŖĀĶĮĮõĖŁ...</div>;

  return (
    <div style={styles.container}>
      <div style={styles.grid}>
        {articles.map(article => (
          <Link to={`/article/${article.id}`} key={article.id} style={styles.card}>
            <img src={article.coverImage || '/placeholder.jpg'} alt={article.title} style={styles.image} />
            <div style={styles.content}>
              <h2 style={styles.title}>{article.title}</h2>
              <div style={styles.meta}>
                <span>{article.author}</span>
                <span>{new Date(article.createdAt).toLocaleDateString('zh-CN')}</span>
              </div>
              <p style={styles.excerpt}>{article.excerpt}</p>
              <div style={styles.tags}>
                {article.tags?.map(tag => (
                  <span key={tag} style={styles.tag}>{tag}</span>
                ))}
              </div>
              <div style={styles.stats}>
                <span style={styles.stat}>ŌØż’ĖÅ {(getArticleStats(article.id).likes ?? article.likes) || 0}</span>
                <span style={styles.stat}>­¤æü’ĖÅ {(getArticleStats(article.id).views ?? article.views) || 0}</span>
              </div>
              {article.isPaid && (
                <span style={styles.paidBadge}>õ╗śĶ┤╣</span>
              )}
            </div>
          </Link>
        ))}
      </div>

      {!user && articles.length >= 3 && (
        <button onClick={handleLoadMore} style={styles.loadMoreBtn}>
          µ¤źń£ŗµø┤ÕżÜµ¢ćń½Ā
        </button>
      )}

      {showRegisterModal && (
        <div style={styles.modal} onClick={() => setShowRegisterModal(false)}>
          <div style={styles.modalContent} onClick={e => e.stopPropagation()}>
            <h2>µ│©ÕåīÕÉÄµ¤źń£ŗµø┤ÕżÜ</h2>
            <p>µ│©ÕåīńÖ╗ÕĮĢÕÉÄÕŹ│ÕÅ»µĄÅĶ¦łÕģ©ķā©µ¢ćń½ĀÕåģÕ«╣</p>
            <Link to="/register" style={styles.modalBtn}>ń½ŗÕŹ│µ│©Õåī</Link>
          </div>
        </div>
      )}
    </div>
  );
};

const styles = {
  container: {
    maxWidth: '1200px',
    margin: '2rem auto',
    padding: '0 1rem',
  },
  loading: {
    textAlign: 'center',
    padding: '4rem',
    fontSize: '1.2rem',
  },
  grid: {
    display: 'grid',
    gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))',
    gap: '2rem',
  },
  card: {
    background: '#fff',
    borderRadius: '12px',
    overflow: 'hidden',
    boxShadow: '0 2px 8px rgba(0,0,0,0.1)',
    transition: 'transform 0.2s',
    position: 'relative',
  },
  image: {
    width: '100%',
    height: '200px',
    objectFit: 'cover',
  },
  content: {
    padding: '1.5rem',
  },
  title: {
    fontSize: '1.25rem',
    marginBottom: '0.5rem',
    color: '#111827',
  },
  meta: {
    display: 'flex',
    justifyContent: 'space-between',
    fontSize: '0.875rem',
    color: '#6b7280',
    marginBottom: '1rem',
  },
  excerpt: {
    color: '#4b5563',
    lineHeight: '1.6',
    marginBottom: '1rem',
  },
  tags: {
    display: 'flex',
    gap: '0.5rem',
    flexWrap: 'wrap',
  },
  tag: {
    background: '#e0e7ff',
    color: '#4f46e5',
    padding: '0.25rem 0.75rem',
    borderRadius: '12px',
    fontSize: '0.75rem',
  },
  stats: {
    display: 'flex',
    gap: '1rem',
    marginTop: '0.5rem',
  },
  stat: {
    fontSize: '0.875rem',
    color: '#6b7280',
    display: 'flex',
    alignItems: 'center',
    gap: '0.25rem',
  },
  paidBadge: {
    position: 'absolute',
    top: '1rem',
    right: '1rem',
    background: '#fbbf24',
    color: '#000',
    padding: '0.25rem 0.75rem',
    borderRadius: '12px',
    fontSize: '0.75rem',
    fontWeight: 'bold',
  },
  loadMoreBtn: {
    display: 'block',
    margin: '2rem auto',
    padding: '1rem 2rem',
    background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
    color: '#fff',
    borderRadius: '24px',
    fontSize: '1rem',
    fontWeight: 'bold',
  },
  modal: {
    position: 'fixed',
    top: 0,
    left: 0,
    right: 0,
    bottom: 0,
    background: 'rgba(0,0,0,0.5)',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    zIndex: 1000,
  },
  modalContent: {
    background: '#fff',
    padding: '2rem',
    borderRadius: '12px',
    textAlign: 'center',
    maxWidth: '400px',
  },
  modalBtn: {
    display: 'inline-block',
    marginTop: '1rem',
    padding: '0.75rem 2rem',
    background: '#667eea',
    color: '#fff',
    borderRadius: '24px',
    fontWeight: 'bold',
  },
};

export default Home;
